import sailpoint.object.Identity;
import sailpoint.tools.GeneralException;
log.error("[CreateContractor] After form reached");

String employeeId = (String) workflow.get("employeeId");
String firstname = (String) workflow.get("firstname");
String lastname = (String) workflow.get("lastname");
String department = (String) workflow.get("department");
String email = (String) workflow.get("email");
String manager = (String) workflow.get("manager");
String status = (String) workflow.get("status");

log.error("[CreateContractor] firstname = " + firstname);
log.error("[CreateContractor] lastname = " + lastname);
log.error("[CreateContractor] employeeId = " + employeeId);

if (employeeId == null || employeeId.trim().length() == 0 ){
	throw new GeneralException("Employee ID is required.");
}

Identity existingIdentity = context.getObjectByName(Identity.class, employeeId); 
if (existingIdentity != null){
	throw new GeneralException("Identity already exists with name/employeeId:");
}

Identity identity = new Identity();
identity.setName(employeeId);
identity.setDisplayName(firstname + " "+ lastname);
identity.setFirstname(firstname);
identity.setLastname(lastname);
identity.setEmail(email);

identity.setAttribute("employeeId", employeeId);
identity.setAttribute("department", department);
identity.setAttribute("manager", manager);
identity.setAttribute("status", status);

context.saveObject(identity);
context.commitTransaction();

log.error("[CreateContractor] Identity created successfully: " + employeeId);
